@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
}
else if (_profile is not null)
{
    <h4 class="mb-4">Profile Settings</h4>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row mb-4">
        <div class="col-md-3 text-center">
            <div class="avatar-preview mb-2">
                @if (!string.IsNullOrWhiteSpace(_profile.AvatarUrl))
                {
                    <img src="@_profile.AvatarUrl" alt="Avatar" class="rounded-circle img-fluid" style="width:120px;height:120px;object-fit:cover;" />
                }
                else
                {
                    <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center" style="width:120px;height:120px;margin:0 auto;">
                        <span class="text-white fs-1">👤</span>
                    </div>
                }
            </div>
            <small class="text-muted text-break">@_profile.AvatarUrl</small>
        </div>
        <div class="col-md-9">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="_profile.DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="_profile.Email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="_profile.Bio"></textarea>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_saving">
            Discard Changes
        </button>
    </div>
}

@code {
    private ProfileModel? _profile;
    private UserProfile? _savedSnapshot;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var data = await SettingsService.GetProfileAsync();
        _savedSnapshot = data;
        _profile = new ProfileModel(data);
        _loading = false;
    }

    private async Task SaveAsync()
    {
        if (_profile is null) return;
        _saving = true;
        var updated = new UserProfile(_profile.DisplayName, _profile.Email, _profile.AvatarUrl, _profile.Bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedSnapshot = updated;
        _successMessage = "Profile saved successfully!";
        _saving = false;
    }

    private void DiscardChanges()
    {
        if (_savedSnapshot is not null)
        {
            _profile = new ProfileModel(_savedSnapshot);
        }
        _successMessage = null;
    }

    private sealed class ProfileModel
    {
        public string DisplayName { get; set; }
        public string Email { get; set; }
        public string AvatarUrl { get; set; }
        public string Bio { get; set; }

        public ProfileModel(UserProfile p)
        {
            DisplayName = p.DisplayName;
            Email = p.Email;
            AvatarUrl = p.AvatarUrl;
            Bio = p.Bio;
        }
    }
}

@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
}
else if (_prefs is not null)
{
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_prefs.EmailNotifications" />
            <label class="form-check-label fw-semibold" for="emailNotif">Email Notifications</label>
            <div class="form-text">Receive notifications via email</div>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_prefs.PushNotifications" />
            <label class="form-check-label fw-semibold" for="pushNotif">Push Notifications</label>
            <div class="form-text">Receive push notifications in your browser</div>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_prefs.WeeklyDigest" />
            <label class="form-check-label fw-semibold" for="weeklyDigest">Weekly Digest</label>
            <div class="form-text">Receive a weekly summary of activity</div>
        </div>
    </div>

    <h5 class="mb-3">Muted Channels</h5>
    @if (_prefs.AllChannels.Count > 0)
    {
        <div class="list-group mb-4">
            @foreach (var channel in _prefs.AllChannels)
            {
                <label class="list-group-item d-flex align-items-center gap-2">
                    <input class="form-check-input" type="checkbox"
                           checked="@channel.IsMuted"
                           @onchange="e => channel.IsMuted = (bool)(e.Value ?? false)" />
                    <span>@channel.Name</span>
                    @if (channel.IsMuted)
                    {
                        <span class="badge bg-secondary ms-auto">Muted</span>
                    }
                </label>
            }
        </div>
    }
    else
    {
        <p class="text-muted">No channels available.</p>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
        Save Preferences
    </button>
}

@code {
    private PrefsModel? _prefs;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var data = await SettingsService.GetNotificationPrefsAsync();
        _prefs = new PrefsModel(data);
        _loading = false;
    }

    private async Task SaveAsync()
    {
        if (_prefs is null) return;
        _saving = true;
        var mutedChannels = _prefs.AllChannels.Where(c => c.IsMuted).Select(c => c.Name).ToList();
        var updated = new NotificationPrefs(_prefs.EmailNotifications, _prefs.PushNotifications, _prefs.WeeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _successMessage = "Notification preferences saved!";
        _saving = false;
    }

    private sealed class PrefsModel
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<ChannelModel> AllChannels { get; set; }

        public PrefsModel(NotificationPrefs p)
        {
            EmailNotifications = p.EmailNotifications;
            PushNotifications = p.PushNotifications;
            WeeklyDigest = p.WeeklyDigest;
            AllChannels = p.MutedChannels.Select(name => new ChannelModel { Name = name, IsMuted = true }).ToList();
        }
    }

    private sealed class ChannelModel
    {
        public string Name { get; set; } = "";
        public bool IsMuted { get; set; }
    }
}

@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
}
else if (_settings is not null)
{
    <h4 class="mb-4">Security Settings</h4>

    @if (_message is not null)
    {
        <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <!-- Change Password Panel -->
    <div class="card mb-4">
        <div class="card-header d-flex align-items-center justify-content-between"
             role="button" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <strong>Change Password</strong>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>
                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @if (_changingPassword) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Update Password
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-4">
        <div class="card-body d-flex align-items-center justify-content-between">
            <div>
                <strong>Two-Factor Authentication</strong>
                <div class="mt-1">
                    @if (_settings.TwoFactorEnabled)
                    {
                        <span class="badge bg-success">Enabled</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Disabled</span>
                    }
                </div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" checked="@_settings.TwoFactorEnabled" disabled
                       style="transform: scale(1.3);" />
            </div>
        </div>
        @if (_settings.LastPasswordChange.HasValue)
        {
            <div class="card-footer text-muted small">
                Last password change: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </div>
        }
    </div>

    <!-- Active Sessions -->
    <h5 class="mb-3">Active Sessions</h5>
    @if (_settings.Sessions.Count > 0)
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _settings.Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                            <td>
                                @if (session != _settings.Sessions[0])
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
    else
    {
        <p class="text-muted">No active sessions.</p>
    }

    <!-- Revoke Confirmation Dialog -->
    @if (_sessionToRevoke is not null)
    {
        <div class="modal fade show d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                        <p class="text-muted small">This will sign out the device immediately.</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                            @if (_revoking) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private SecuritySettings? _settings;
    private bool _loading = true;
    private string? _message;
    private bool _messageIsError;

    // Password fields
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;

    // Session revocation
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "New password cannot be empty.";
            _messageIsError = true;
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _messageIsError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully!";
            _messageIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to change password: {ex.Message}";
            _messageIsError = true;
        }
        _changingPassword = false;
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null || _settings is null) return;
        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _settings = _settings with
            {
                Sessions = _settings.Sessions.Where(s => s.Id != _sessionToRevoke.Id).ToList()
            };
            _message = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to revoke session: {ex.Message}";
            _messageIsError = true;
        }
        _sessionToRevoke = null;
        _revoking = false;
    }
}

