@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="container-fluid py-4">
    <h2 class="mb-4">Settings</h2>
    <div class="row">
        <div class="col-md-3 col-lg-2 mb-3">
            <SettingsSidebar ActiveSection="@_activeSection"
                             OnSectionChanged="section => _activeSection = section" />
        </div>
        <div class="col-md-9 col-lg-10">
            <div class="card">
                <div class="card-body">
                    @switch (_activeSection)
                    {
                        case "Profile":
                            <ProfileSection />
                            break;
                        case "Notifications":
                            <NotificationsSection />
                            break;
                        case "Security":
                            <SecuritySection />
                            break;
                        case "Appearance":
                            <AppearanceSection />
                            break;
                    }
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

